	append_u32(mut out, 0x18b7a10d)
	mut flags := 0
	if d.ipv6 {
		flags |= 1 << 0
	}
	if d.media_only {
		flags |= 1 << 1
	}
	if d.tcpo_only {
		flags |= 1 << 2
	}
	if d.cdn {
		flags |= 1 << 3
	}
	if d.static_value {
		flags |= 1 << 4
	}
	if d.this_port_only {
		flags |= 1 << 5
	}
	if d.has_secret_value {
		flags |= 1 << 10
	}
	append_int(mut out, flags)
	append_int(mut out, d.id)
	append_string(mut out, d.ip_address)
	append_int(mut out, d.port)
	if d.has_secret_value {
		append_bytes(mut out, d.secret)
	}
	return out
}

