fn decode_document_body(mut decoder Decoder) !Document {
	mut id := i64(0)
	mut access_hash := i64(0)
	mut file_reference := []u8{}
	mut date := 0
	mut mime_type := ''
	mut size := i64(0)
	mut thumbs := []PhotoSizeType{}
	mut has_thumbs_value := false
	mut video_thumbs := []VideoSizeType{}
	mut has_video_thumbs_value := false
	mut dc_id := 0
	mut attributes := []DocumentAttributeType{}
	mut flags := 0
	flags = decoder.read_int()!
	id = decoder.read_long()!
	access_hash = decoder.read_long()!
	file_reference = decoder.read_bytes()!
	date = decoder.read_int()!
	mime_type = decoder.read_string()!
	size = decoder.read_long()!
	if (flags & (1 << 0)) != 0 {
		tl_tmp_thumbs_count := decoder.read_vector_len()!
		thumbs = []PhotoSizeType{}
		for _ in 0 .. tl_tmp_thumbs_count {
			thumbs << decode_photo_size_type_from_decoder(mut decoder)!
		}
		has_thumbs_value = true
	}
	if (flags & (1 << 1)) != 0 {
		tl_tmp_video_thumbs_count := decoder.read_vector_len()!
		video_thumbs = []VideoSizeType{}
		for _ in 0 .. tl_tmp_video_thumbs_count {
			video_thumbs << decode_video_size_type_from_decoder(mut decoder)!
		}
		has_video_thumbs_value = true
	}
	dc_id = decoder.read_int()!
	tl_tmp_attributes_count := decoder.read_vector_len()!
	attributes = []DocumentAttributeType{}
	for _ in 0 .. tl_tmp_attributes_count {
		attributes << decode_document_attribute_type_from_decoder(mut decoder)!
	}
	return Document{
		id:                     id
		access_hash:            access_hash
		file_reference:         file_reference
		date:                   date
		mime_type:              mime_type
		size:                   size
		thumbs:                 thumbs
		has_thumbs_value:       has_thumbs_value
		video_thumbs:           video_thumbs
		has_video_thumbs_value: has_video_thumbs_value
		dc_id:                  dc_id
		attributes:             attributes
	}
}

