	email_to_provider               bool
	recurring                       bool
	currency                        string
	prices                          []LabeledPriceType
	max_tip_amount                  i64
	has_max_tip_amount_value        bool
	suggested_tip_amounts           []i64
	has_suggested_tip_amounts_value bool
