pub fn (i Invoice) constructor_id() u32 {
	return 0x049ee584
}

pub fn (i Invoice) qualified_name() string {
	return 'invoice'
}

pub fn (i Invoice) encode() ![]u8 {
	mut out := []u8{}
	append_u32(mut out, 0x049ee584)
	mut flags := 0
	if i.test {
		flags |= 1 << 0
	}
	if i.name_requested {
		flags |= 1 << 1
	}
	if i.phone_requested {
		flags |= 1 << 2
	}
	if i.email_requested {
		flags |= 1 << 3
	}
	if i.shipping_address_requested {
		flags |= 1 << 4
	}
	if i.flexible {
		flags |= 1 << 5
	}
	if i.phone_to_provider {
		flags |= 1 << 6
	}
	if i.email_to_provider {
		flags |= 1 << 7
	}
	if i.has_max_tip_amount_value != i.has_suggested_tip_amounts_value {
		return error('inconsistent presence for invoice flags.8')
	}
	if i.has_max_tip_amount_value {
		flags |= 1 << 8
	}
	if i.recurring {
		flags |= 1 << 9
	}
	if i.has_terms_url_value {
		flags |= 1 << 10
	}
	if i.has_subscription_period_value {
		flags |= 1 << 11
	}
	append_int(mut out, flags)
	append_string(mut out, i.currency)
	append_u32(mut out, vector_constructor_id)
	append_int(mut out, i.prices.len)
	for tl_tmp_item_i_prices in i.prices {
		out << tl_tmp_item_i_prices.encode()!
	}
	if i.has_max_tip_amount_value {
		append_long(mut out, i.max_tip_amount)
	}
	if i.has_suggested_tip_amounts_value {
		append_u32(mut out, vector_constructor_id)
		append_int(mut out, i.suggested_tip_amounts.len)
		for tl_tmp_item_i_suggested_tip_amounts in i.suggested_tip_amounts {
			append_long(mut out, tl_tmp_item_i_suggested_tip_amounts)
		}
	}
	if i.has_terms_url_value {
		append_string(mut out, i.terms_url)
	}
	if i.has_subscription_period_value {
		append_int(mut out, i.subscription_period)
	}
	return out
}

fn decode_invoice_body(mut decoder Decoder) !Invoice {
	mut test := false
	mut name_requested := false
	mut phone_requested := false
	mut email_requested := false
	mut shipping_address_requested := false
	mut flexible := false
	mut phone_to_provider := false
	mut email_to_provider := false
	mut recurring := false
	mut currency := ''
	mut prices := []LabeledPriceType{}
	mut max_tip_amount := i64(0)
	mut has_max_tip_amount_value := false
	mut suggested_tip_amounts := []i64{}
	mut has_suggested_tip_amounts_value := false
	mut terms_url := ''
	mut has_terms_url_value := false
	mut subscription_period := 0
	mut has_subscription_period_value := false
	mut flags := 0
	flags = decoder.read_int()!
	test = (flags & (1 << 0)) != 0
	name_requested = (flags & (1 << 1)) != 0
	phone_requested = (flags & (1 << 2)) != 0
	email_requested = (flags & (1 << 3)) != 0
	shipping_address_requested = (flags & (1 << 4)) != 0
	flexible = (flags & (1 << 5)) != 0
	phone_to_provider = (flags & (1 << 6)) != 0
	email_to_provider = (flags & (1 << 7)) != 0
	recurring = (flags & (1 << 9)) != 0
	currency = decoder.read_string()!
	tl_tmp_prices_count := decoder.read_vector_len()!
	prices = []LabeledPriceType{}
	for _ in 0 .. tl_tmp_prices_count {
		prices << decode_labeled_price_type_from_decoder(mut decoder)!
	}
	if (flags & (1 << 8)) != 0 {
		max_tip_amount = decoder.read_long()!
		has_max_tip_amount_value = true
	}
	if (flags & (1 << 8)) != 0 {
		tl_tmp_suggested_tip_amounts_count := decoder.read_vector_len()!
		suggested_tip_amounts = []i64{}
		for _ in 0 .. tl_tmp_suggested_tip_amounts_count {
			suggested_tip_amounts << decoder.read_long()!
		}
		has_suggested_tip_amounts_value = true
	}
	if (flags & (1 << 10)) != 0 {
		terms_url = decoder.read_string()!
		has_terms_url_value = true
	}
	if (flags & (1 << 11)) != 0 {
		subscription_period = decoder.read_int()!
		has_subscription_period_value = true
	}
	return Invoice{
		test:                            test
		name_requested:                  name_requested
		phone_requested:                 phone_requested
		email_requested:                 email_requested
		shipping_address_requested:      shipping_address_requested
		flexible:                        flexible
		phone_to_provider:               phone_to_provider
		email_to_provider:               email_to_provider
		recurring:                       recurring
		currency:                        currency
		prices:                          prices
		max_tip_amount:                  max_tip_amount
		has_max_tip_amount_value:        has_max_tip_amount_value
		suggested_tip_amounts:           suggested_tip_amounts
		has_suggested_tip_amounts_value: has_suggested_tip_amounts_value
		terms_url:                       terms_url
		has_terms_url_value:             has_terms_url_value
		subscription_period:             subscription_period
		has_subscription_period_value:   has_subscription_period_value
	}
}

