	call_requests_disabled                bool
	has_call_requests_disabled_value      bool
}

pub fn (a AccountChangeAuthorizationSettings) constructor_id() u32 {
	return 0x40f48462
}

pub fn (a AccountChangeAuthorizationSettings) qualified_name() string {
	return 'account.changeAuthorizationSettings'
}

pub fn (a AccountChangeAuthorizationSettings) encode() ![]u8 {
	mut out := []u8{}
	append_u32(mut out, 0x40f48462)
	mut flags := 0
	if a.has_encrypted_requests_disabled_value {
		flags |= 1 << 0
	}
	if a.has_call_requests_disabled_value {
		flags |= 1 << 1
	}
	if a.confirmed {
		flags |= 1 << 3
	}
	append_int(mut out, flags)
	append_long(mut out, a.hash)
	if a.has_encrypted_requests_disabled_value {
		append_bool(mut out, a.encrypted_requests_disabled)
	}
	if a.has_call_requests_disabled_value {
		append_bool(mut out, a.call_requests_disabled)
	}
	return out
}

fn decode_account_change_authorization_settings_body(mut decoder Decoder) !AccountChangeAuthorizationSettings {
	mut confirmed := false
	mut hash := i64(0)
	mut encrypted_requests_disabled := false
	mut has_encrypted_requests_disabled_value := false
	mut call_requests_disabled := false
	mut has_call_requests_disabled_value := false
	mut flags := 0
	flags = decoder.read_int()!
	confirmed = (flags & (1 << 3)) != 0
	hash = decoder.read_long()!
	if (flags & (1 << 0)) != 0 {
		encrypted_requests_disabled = decoder.read_bool()!
		has_encrypted_requests_disabled_value = true
	}
	if (flags & (1 << 1)) != 0 {
		call_requests_disabled = decoder.read_bool()!
		has_call_requests_disabled_value = true
	}
	return AccountChangeAuthorizationSettings{
		confirmed:                             confirmed
		hash:                                  hash
		encrypted_requests_disabled:           encrypted_requests_disabled
		has_encrypted_requests_disabled_value: has_encrypted_requests_disabled_value
		call_requests_disabled:                call_requests_disabled
		has_call_requests_disabled_value:      has_call_requests_disabled_value
	}
}

