	return 0xd69b8361
}

pub fn (a AccountSaveAutoSaveSettings) qualified_name() string {
	return 'account.saveAutoSaveSettings'
}

pub fn (a AccountSaveAutoSaveSettings) encode() ![]u8 {
	mut out := []u8{}
	append_u32(mut out, 0xd69b8361)
	mut flags := 0
	if a.users {
		flags |= 1 << 0
	}
	if a.chats {
		flags |= 1 << 1
	}
	if a.broadcasts {
		flags |= 1 << 2
	}
	if a.has_peer_value {
		flags |= 1 << 3
	}
	append_int(mut out, flags)
	if a.has_peer_value {
		out << a.peer.encode()!
	}
	out << a.settings.encode()!
	return out
}

