	if c.has_geo_point_value {
		flags |= 1 << 2
	}
	if c.for_import {
		flags |= 1 << 3
	}
	if c.has_ttl_period_value {
		flags |= 1 << 4
	}
	if c.forum {
		flags |= 1 << 5
	}
	append_int(mut out, flags)
	append_string(mut out, c.title)
	append_string(mut out, c.about)
	if c.has_geo_point_value {
		out << c.geo_point.encode()!
	}
	if c.has_address_value {
		append_string(mut out, c.address)
	}
	if c.has_ttl_period_value {
		append_int(mut out, c.ttl_period)
	}
	return out
}

